            self._.update(
                DEV=(env == "development"),
                PROD=(env == "production"),
                env=env,
                origin=get_app_origin(),
            )

        @property
        def DEV(self) -> bool:
            return self._["DEV"]

        @property
        def PROD(self) -> bool:
            return self._["PROD"]

        @property
        def env(self) -> str:
            return self._["env"]

        @property
        def origin(self) -> str:
            return self._["origin"]

    meta = Meta()

    return meta

